            Log.i(TAG, "Task $taskId completed: ${result.success} - ${result.message}")

            sendCallback(intent, taskId, result)

            activeTasks.remove(taskId)

            if (activeTasks.isEmpty()) {
                updateNotification("All tasks completed")
                stopForeground(STOP_FOREGROUND_REMOVE)
                stopSelfResult(startId)
            }
        }
    }

