    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "onStartCommand received with startId: $startId")

        startForeground(NOTIFICATION_ID, createNotification("Processing maintenance tasks..."))

        if (intent == null) {
            Log.w(TAG, "Received null intent, stopping")
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)
        if (taskType.isNullOrEmpty()) {
            Log.w(TAG, "No task type specified")
            sendCallback(intent, -1, TaskResult(false, "No task type specified"))
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        if (!isValidTaskType(taskType)) {
            Log.w(TAG, "Invalid task type: $taskType")
            sendCallback(intent, -1, TaskResult(false, "Invalid task type: $taskType"))
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val callerPackage = intent.getStringExtra(EXTRA_CALLBACK_PACKAGE)
            ?: getCallingPackage(intent)

        if (!isAuthorizedCaller(callerPackage)) {
            Log.w(TAG, "Unauthorized caller: $callerPackage")
            sendCallback(intent, -1, TaskResult(false, "Unauthorized caller"))
            stopSelfResult(startId)
            return START_NOT_STICKY
        }

        val taskId = taskCounter.incrementAndGet()
        val priority = intent.getIntExtra(EXTRA_PRIORITY, PRIORITY_NORMAL)

        val taskInfo = TaskInfo(
            taskId = taskId,
            taskType = taskType,
            startTime = System.currentTimeMillis(),
            callerPackage = callerPackage,
            priority = priority
        )
        activeTasks[taskId] = taskInfo

        val msg = serviceHandler.obtainMessage().apply {
            arg1 = startId
            arg2 = taskId
            obj = intent
        }

        when (priority) {
            PRIORITY_HIGH -> serviceHandler.sendMessageAtFrontOfQueue(msg)
            else -> serviceHandler.sendMessage(msg)
        }

        Log.i(TAG, "Task $taskId queued: $taskType (priority: $priority)")

        return START_REDELIVER_INTENT
    }

