            TASK_TYPE_FULL_MAINTENANCE -> performFullMaintenance(intent, taskId)
            else -> TaskResult(false, "Unknown task type: $taskType")
        }
    }

    private fun performDataSync(intent: Intent, taskId: Int): TaskResult {
